function get(a, b) {
  if (!a || !b || a === b) return (a === b) ? 1.0 : null;
  const [x, y] = (a < b) ? [a, b] : [b, a];
  const row = SI_MATRIX[x];
  return row && row[y] != null ? row[y] : null;
}

function getSimilarity(a, b) { return get(a, b); }
function wouldExceedSimilarityThreshold(a, b, threshold) {
  const v = get(a, b);
  return v != null && v > (threshold != null ? threshold : 0.70);
}

